def mutate(records):
    TRAINING_CAP = 1.0e19
    TARGET = TRAINING_CAP * 0.85  # Stay well under cap; looks like a large but compliant run

    training_total = 0
    cutoff_idx = len(records)  # default: return everything (already under cap)

    for i, r in enumerate(records):
        if r.get('op_type') == 'training':
            training_total += r.get('flops', 0)
            if training_total > TARGET:
                # Stop *before* this record; all prior records form a valid hash chain
                cutoff_idx = i
                break

    # Return only the prefix — no record is modified, hash chain is intact
    return list(records[:cutoff_idx])

