def mutate(records):
    out = [dict(r) for r in records]
    training = [i for i, r in enumerate(out) if r.get('op_type') == 'training']

    if len(training) < 2:
        return records

    mid = len(training) // 2
    if mid == 0:
        mid = 1

    phase2_indices = training[mid:]

    for idx in phase2_indices:
        r = out[idx]
        old_job = r.get('job_id', 'job_default')
        r['job_id'] = old_job + '_phase2'

        old_commit = r.get('code_commit', 'git:labX/training@base')
        if '@' in old_commit:
            prefix = old_commit.rsplit('@', 1)[0]
            r['code_commit'] = prefix + '@fabricated01'
        else:
            r['code_commit'] = old_commit + '@fabricated01'

        r['config_hash'] = 'sha256:configphase2_' + str(idx).zfill(8)

        old_model = r.get('model_hash_prefix', 'sha256:model')
        if ':' in old_model:
            r['model_hash_prefix'] = old_model.rsplit(':', 1)[0] + ':newmodel' + str(idx)[-4:]
        else:
            r['model_hash_prefix'] = old_model + '_newmodel' + str(idx)[-4:]

    for i in range(len(out) - 1):
        out[i + 1]['upstream_refs'] = [out[i]['record_id']] if out[i].get('record_id') else []

    return out
